              </div>
            </div>

            <div className="absolute bottom-3 md:bottom-4 left-3 md:left-4 right-3 md:right-4 flex justify-between items-center mt-2 md:mt-4 border-t border-gray-100 md:border-gray-200 pt-2 md:pt-3">
